import { TaskPriority } from './TaskPriority.js';

/**
 * Task execution context containing timing and state information
 */
export interface TaskContext {
  /** Current high-precision timestamp */
  currentTime: number;
  /** Time when this task was scheduled to execute */
  scheduledTime: number;
  /** Delta between scheduled and actual execution time */
  timingError: number;
  /** Frame number for display-synchronized tasks */
  frameNumber: number;
  /** Whether this task is running behind schedule */
  isLate: boolean;
}

/**
 * Task execution function signature
 */
export type TaskFunction = (context: TaskContext) => Promise<void> | void;

/**
 * Task completion callback signature
 */
export type TaskCompletionCallback = (task: Task, error?: Error) => void;

/**
 * Configuration options for task creation
 */
export interface TaskOptions {
  /** Task priority level */
  priority?: TaskPriority;
  /** Maximum execution time in milliseconds */
  timeout?: number;
  /** Whether task can be interrupted by higher priority tasks */
  interruptible?: boolean;
  /** Arbitrary metadata for the task */
  metadata?: Record<string, unknown>;
  /** Completion callback */
  onComplete?: TaskCompletionCallback;
  /** Error callback */
  onError?: TaskCompletionCallback;
}

/**
 * Task execution state
 */
export enum TaskState {
  PENDING = 'pending',
  RUNNING = 'running',
  COMPLETED = 'completed',
  FAILED = 'failed',
  CANCELLED = 'cancelled'
}

